svg.script:
(function(){
  var svg=document.querySelector('svg'),
      g=document.getElementById('tooltip'),
      bg=document.getElementById('tip-bg'),
      t1=document.getElementById('tip-t1'),
      t2=document.getElementById('tip-t2');
  svg.addEventListener('mousemove',function(e){
    var el=e.target.closest('[data-tip]');
    if(!el){g.setAttribute('opacity','0');return;}
    var lines=el.getAttribute('data-tip').split('|');
    t1.textContent=lines[0]||'';
    t2.textContent=lines[1]||'';
    var pt=svg.createSVGPoint();
    pt.x=e.clientX; pt.y=e.clientY;
    var p=pt.matrixTransform(svg.getScreenCTM().inverse());
    var w=Math.max(t1.getComputedTextLength(),t2.getComputedTextLength())+16;
    var h=lines[1]?44:24;
    bg.setAttribute('width',w);
    bg.setAttribute('height',h);
    var tx=p.x+12, ty=p.y-h-6;
    if(tx+w>1600) tx=p.x-w-12;
    if(ty<0) ty=p.y+16;
    g.setAttribute('transform','translate('+tx+','+ty+')');
    g.setAttribute('opacity','1');
  });
})();
